const amqp = require('amqplib');
const { Client } = require('pg'); // Assuming PostgreSQL for database
const dotenv = require('dotenv');
const Joi = require('joi');

dotenv.config();

const dbClient = new Client({
  connectionString: process.env.DATABASE_URL,
});
dbClient.connect();

const messageSchema = Joi.object({
  type: Joi.string().valid('create', 'update', 'delete').required(),
  payload: Joi.object().required(),
});

async function processMessage(msg) {
  const content = msg.content.toString();
  
  try {
    const parsedMessage = JSON.parse(content);
    const { error } = messageSchema.validate(parsedMessage);
    
    if (error) {
      console.error('Invalid message format:', error.details);
      return;
    }

    switch (parsedMessage.type) {
      case 'create':
        await handleCreate(parsedMessage.payload);
        break;
      case 'update':
        await handleUpdate(parsedMessage.payload);
        break;
      case 'delete':
        await handleDelete(parsedMessage.payload);
        break;
      default:
        console.error('Unknown message type:', parsedMessage.type);
    }
  } catch (err) {
    console.error('Error processing message:', err);
  }
}

async function handleCreate(payload) {
  const { name, value } = payload;
  const query = 'INSERT INTO items(name, value) VALUES($1, $2)';
  await dbClient.query(query, [name, value]);
}

async function handleUpdate(payload) {
  const { id, name, value } = payload;
  const query = 'UPDATE items SET name = $1, value = $2 WHERE id = $3';
  await dbClient.query(query, [name, value, id]);
}

async function handleDelete(payload) {
  const { id } = payload;
  const query = 'DELETE FROM items WHERE id = $1';
  await dbClient.query(query, [id]);
}

async function start() {
  try {
    const connection = await amqp.connect(process.env.RABBITMQ_URL);
    const channel = await connection.createChannel();
    const queue = 'my_queue';

    await channel.assertQueue(queue, { durable: true });
    console.log('Waiting for messages in %s', queue);

    channel.consume(queue, async (msg) => {
      if (msg !== null) {
        await processMessage(msg);
        channel.ack(msg);
      }
    });
  } catch (err) {
    console.error('Error connecting to RabbitMQ:', err);
  }
}

start();